import XCTest
import WebKit
@testable import NHSOnline

class HomeViewControllerTests: XCTestCase {
    var vcHome: HomeViewController!
    var testWebview: WKWebView!

    var mockConfigurationService: MockConfigurationService!
    var mockApplicationState: MockApplicationState!

    let app = XCUIApplication.self

    override func setUp() {
        super.setUp()
        
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let vc: HomeViewController = storyboard.instantiateViewController(withIdentifier: "HomeViewController") as! HomeViewController
        testWebview = WKWebView()
        vcHome = vc
        _ = vcHome.view

        mockConfigurationService = MockConfigurationService();
        vcHome?.configurationService = mockConfigurationService
        
        mockApplicationState = MockApplicationState();
        vcHome?.applicationState = mockApplicationState
    }
    
    func test_hasCidUrlSuffix_nilUrl_Returns_False() {
        let testResult = vcHome.hasCidUrlSuffix(webview: testWebview)
       
        XCTAssertFalse(testResult)
    }

    func test_hasCidUrlSuffix_NormalUrl_Returns_False() {
        testWebview.load(URLRequest(url: URL(string: "https://www.google.com/")!))
        
        let testResult = vcHome.hasCidUrlSuffix(webview: testWebview)
        
        XCTAssertFalse(testResult)
    }
    
    func test_hasCidUrlSuffix_CidSuffixUrl_Returns_True() {
        testWebview.load(URLRequest(url: (URL(string: "https://www.google.com/")?.appendingPathComponent(config().CidUrlSuffix))!))
        
        let testResult = vcHome.hasCidUrlSuffix(webview: testWebview)
        
        XCTAssertTrue(testResult)
    }
    
    func test_isCheckYourSymptomsPath_RandomUrl_Returns_False() {
        testWebview.load(URLRequest(url: URL(string: "https://www.google.com/")!))
        
        let testResult = vcHome.isCheckYourSymptomsPath(webview: testWebview)
        
        XCTAssertFalse(testResult)
    }
    
    func test_isCheckYourSymptomsPath_BaseHostNoPath_Returns_False() {
        testWebview.load(URLRequest(url: URL(string: config().HomeUrl)!))
        
        let testResult = vcHome.isCheckYourSymptomsPath(webview: testWebview)
        
        XCTAssertFalse(testResult)
    }
    
    func test_isCheckYourSymptomsPath_NilUrl_Returns_False() {
        let testResult = vcHome.isCheckYourSymptomsPath(webview: testWebview)
        
        XCTAssertFalse(testResult)
    }
    
    func test_isCheckYourSymptomsPath_CorrectBaseHost_AndSymptomsPath_Returns_True() {
        let symptomsPath = config().CheckSymptomsUrlPath

        testWebview.load(URLRequest(url: ((URL(string: config().HomeUrl)?.appendingPathComponent(String(symptomsPath.dropFirst())))!)))
        
        let testResult = vcHome.isCheckYourSymptomsPath(webview: testWebview)
        
        XCTAssertTrue(testResult)
    }
    
    func test_delayedBiometricsStart_shouldClearMenuBar() {
        
        testWebview.load(URLRequest(url: ((URL(string:
            config().HomeUrl + "login")!))))
        vcHome.selectedTab = 1
        
        vcHome.checkForLoginPageAndTriggerBiometricTimer(testWebview, 10)
        
        XCTAssert(vcHome?.selectedTab == nil)
    }
    
    func test_biometricsShownIfAppVersionIsValidAndBiometricsIsAvailable() {
        self.mockConfigurationService?.isValidConfiguration = true
        
        vcHome.attemptBiometricLoginIfAppVersionValid()

        assert(vcHome.biometricsHasBeenAttempted == true)
    }
    
    func test_biometricsNotShownIfAppVersionIsInvalid() {
        self.mockConfigurationService?.isValidConfiguration = false
        
        vcHome.attemptBiometricLoginIfAppVersionValid()

        assert(vcHome.biometricsHasBeenAttempted == false)
    }
    
    func test_startDownload_image() {
        
        let documentInteractionController = MockDocumentInteractionController()
        vcHome.documentInteractionController = documentInteractionController
        
        vcHome.downloadFile(messageBody: "data:image/bmp;base64,|split|text.bmp|split|image/bmp")
        
        XCTAssert(documentInteractionController.menuOpened == true,
        "Expected the presentOptionsMenu to be called")
    }
    
    func test_startDownload_pdf() {
        
        let documentInteractionController = MockDocumentInteractionController()
        vcHome.documentInteractionController = documentInteractionController
        
        vcHome.downloadFile(messageBody: "application/pdf;base64,|split|test.pdf|split|application/pdf")
        
        XCTAssert(documentInteractionController.menuOpened == true,
        "Expected the presentOptionsMenu to be called")
    }
    
    func test_startDownload_docx() {
        
        let documentInteractionController = MockDocumentInteractionController()
        vcHome.documentInteractionController = documentInteractionController
        
        
        vcHome.downloadFile(messageBody: "data:application/msword;base64,|split|test.docx|split|application/msword")
            
        XCTAssert(documentInteractionController.menuOpened == true,
        "Expected the presentOptionsMenu to be called")
    }
    
    func test_showWebViewContainer_isBlockedisFalse() {
        vcHome.showWebViewContainer()
        assert(self.mockApplicationState.isBlocked == false)
    }
    
    class MockApplicationState: ApplicationState {
        var isBlocked = false
        
        override func block() {
            isBlocked = true
        }
    
        override func unBlock() {
            isBlocked = false
        }
    }
    
    class MockDocumentInteractionController: UIDocumentInteractionController {
        var menuOpened = false
        
        override func presentOpenInMenu(from rect: CGRect, in view: UIView, animated: Bool) -> Bool {
            menuOpened = true;
            return true;        }
        override func presentOptionsMenu(from rect: CGRect, in view: UIView, animated: Bool) -> Bool {
        menuOpened = true;
        return true;        }
    }
    
    class MockConfigurationService: ConfigurationServiceProtocol {
        var isValidConfiguration = false
        
        func isUserDeviceAllowed(homeViewController: HomeViewController, completionHandler: @escaping (ConfigurationResponse?) -> Void) {
            
            let response = ConfigurationResponse(isValidConfiguration, "", false)
            completionHandler(response)
        }
    }
}
